// Itera sobre cada email recebido e cria um item por anexo PDF
const results = [];

for (const item of $input.all()) {
  const binary = item.binary || {};
  const meta = {
    from: item.json.from || (item.json.headers && item.json.headers.from) || '',
    subject: item.json.subject || (item.json.headers && item.json.headers.subject) || '',
    date: item.json.date || (item.json.headers && item.json.headers.date) || '',
    messageId: item.json.messageId || '',
  };

  for (const key of Object.keys(binary)) {
    const b = binary[key];
    if (!b) continue;
    const name = (b.fileName || '').toLowerCase();
    const mime = (b.mimeType || '').toLowerCase();
    const isPdf = mime === 'application/pdf' || name.endsWith('.pdf');
    if (!isPdf) continue;

    results.push({
      json: {
        ...meta,
        originalFileName: b.fileName || 'fatura.pdf',
      },
      binary: {
        data: b,
      },
      pairedItem: { item: 0 },
    });
  }
}

if (results.length === 0) {
  return [];
}
return results;

// Extrai CLIENTE, UNIDADE CONSUMIDORA e MES de REFERENCIA do texto da fatura Energisa
// e monta o caminho de armazenamento no Supabase: CLIENTE/UC/FATURA-MES.pdf

const MESES_PT = {
  JAN: '01', FEV: '02', MAR: '03', ABR: '04', MAI: '05', JUN: '06',
  JUL: '07', AGO: '08', SET: '09', OUT: '10', NOV: '11', DEZ: '12',
};

function sanitize(str, max = 80) {
  return (str || 'DESCONHECIDO')
    .toString()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^A-Za-z0-9\-]+/g, '_')
    .replace(/^_+|_+$/g, '')
    .replace(/_+/g, '_')
    .toUpperCase()
    .slice(0, max) || 'DESCONHECIDO';
}

function normalizarMes(raw) {
  if (!raw) return null;
  const s = raw.toString().trim().toUpperCase();
  // formato MM/AAAA
  let m = s.match(/^(\d{2})\/(\d{4})$/);
  if (m) return `${m[2]}-${m[1]}`;
  // formato NOME/AAAA (JAN/2026)
  m = s.match(/^([A-Z]{3,})[\/\- ](\d{4})$/);
  if (m) {
    const mm = MESES_PT[m[1].slice(0, 3)];
    if (mm) return `${m[2]}-${mm}`;
  }
  // formato NOME AAAA
  m = s.match(/^([A-Z]{3,})\s*(\d{4})$/);
  if (m) {
    const mm = MESES_PT[m[1].slice(0, 3)];
    if (mm) return `${m[2]}-${mm}`;
  }
  return null;
}

const results = [];

for (const item of $input.all()) {
  const text = (item.json.text || '').replace(/\r/g, '');

  // CLIENTE / Razao social
  let cliente = null;
  const regexesCliente = [
    /NOME\s*\/?\s*RAZ[ÃA]O\s*SOCIAL[:\s]+([^\n]+)/i,
    /RAZ[ÃA]O\s*SOCIAL[:\s]+([^\n]+)/i,
    /CLIENTE[:\s]+([^\n]+)/i,
    /NOME[:\s]+([^\n]+)/i,
  ];
  for (const r of regexesCliente) {
    const m = text.match(r);
    if (m && m[1]) { cliente = m[1].trim(); break; }
  }

  // UNIDADE CONSUMIDORA
  let uc = null;
  const regexesUC = [
    /UNIDADE\s*CONSUMIDORA[:\s\-Nn°ºo\.]*([0-9]{5,})/i,
    /N[ºo°]?\s*DA\s*INSTALA[CÇ][AÃ]O[:\s]*([0-9]{5,})/i,
    /INSTALA[CÇ][AÃ]O[:\s]*([0-9]{5,})/i,
    /\bUC[:\s\-Nn°º]*([0-9]{5,})/i,
  ];
  for (const r of regexesUC) {
    const m = text.match(r);
    if (m && m[1]) { uc = m[1].trim(); break; }
  }

  // MES DE REFERENCIA
  let mesRaw = null;
  const regexesMes = [
    /M[ÊE]S\s*(?:DE)?\s*REFER[ÊE]NCIA[:\s]+([A-Z]{3,}[\/\- ]\d{4}|\d{2}\/\d{4})/i,
    /REFER[ÊE]NCIA[:\s]+([A-Z]{3,}[\/\- ]\d{4}|\d{2}\/\d{4})/i,
    /COMPET[ÊE]NCIA[:\s]+([A-Z]{3,}[\/\- ]\d{4}|\d{2}\/\d{4})/i,
  ];
  for (const r of regexesMes) {
    const m = text.match(r);
    if (m && m[1]) { mesRaw = m[1].trim(); break; }
  }

  const mesNorm = normalizarMes(mesRaw) || new Date().toISOString().slice(0, 7);

  const clienteSan = sanitize(cliente);
  const ucSan = sanitize(uc);
  const mesSan = mesNorm.replace(/[^0-9\-]/g, '');

  const path = `${clienteSan}/${ucSan}/FATURA-${mesSan}.pdf`;

  results.push({
    json: {
      cliente: clienteSan,
      unidade_consumidora: ucSan,
      mes_referencia: mesSan,
      path,
      originalFileName: item.json.originalFileName,
      from: item.json.from,
      subject: item.json.subject,
      date: item.json.date,
    },
    binary: item.binary,
  });
}

return results;

// Loga resultado do upload com o caminho final
const results = [];
for (const item of $input.all()) {
  results.push({
    json: {
      ok: true,
      path: item.json.Key || item.json.path || null,
      cliente: item.json.cliente,
      unidade_consumidora: item.json.unidade_consumidora,
      mes_referencia: item.json.mes_referencia,
      originalFileName: item.json.originalFileName,
      publicUrl: `${$env.SUPABASE_URL}/storage/v1/object/public/faturas/${encodeURI(item.json.path || '')}`,
    },
  });
}
return results;
